final:
module decoder_2to4(_invertedA, E, Y);
    input [1:0] _invertedA;
    input E;
    output reg [3:0] Y;

    always @(_invertedA or E) begin
        if (E)
            case (_invertedA)
                2'b00: Y = 4'b0001;
                2'b01: Y = 4'b0010;
                2'b10: Y = 4'b0100;
                2'b11: Y = 4'b1000;
                default: Y = 4'b0000;
            endcase
        else
            Y = 4'b0000;
    end
endmodule
